with open('task/5/EmitMIR.cpp', 'r') as f:
    lines = f.readlines()

# Find the exact range to replace
start_idx = None
end_idx = None
for i, line in enumerate(lines):
    if 'TASK 5 START' in line:
        # Go back to find `*/` (the opening of the comment block)
        for j in range(i, -1, -1):
            if '/*' in lines[j] and 'TASK' not in lines[j]:
                start_idx = j
                break
    if start_idx is not None and 'TASK 5 END' in line:
        # Go forward to find `*/` (the closing of the comment block)
        for j in range(i, len(lines)):
            if '*/' in lines[j] and 'TASK' not in lines[j]:
                end_idx = j
                break
        break

print(f"Replacing lines {start_idx+1} to {end_idx+1}")

new_code = '''  /*
  ----------------------------------------------------------------
  TASK 5 START
  ----------------------------------------------------------------
  */

  void emitBinary(const llvm::BinaryOperator& bo)
  {
    llvm::Register dst = vregOf(&bo);
    llvm::Register lhs = emitLoadValue(bo.getOperand(0));
    llvm::Register rhs = emitLoadValue(bo.getOperand(1));
    auto op = bo.getOpcode();

    switch (op) {
      case llvm::Instruction::Add:
        emitVAdd(dst, lhs, rhs);
        return;
      case llvm::Instruction::Sub:
        emitVSub(dst, lhs, rhs);
        return;
      case llvm::Instruction::Mul:
        emitVMul(dst, lhs, rhs);
        return;
      case llvm::Instruction::SDiv:
        emitVDiv(dst, lhs, rhs);
        return;
      case llvm::Instruction::SRem:
        emitVRem(dst, lhs, rhs);
        return;
      case llvm::Instruction::And:
        emitMC(llvm::RISCV::AND, { mcReg(dst), mcReg(lhs), mcReg(rhs) });
        return;
      case llvm::Instruction::Or:
        emitMC(llvm::RISCV::OR, { mcReg(dst), mcReg(lhs), mcReg(rhs) });
        return;
      case llvm::Instruction::Xor:
        emitVXor(dst, lhs, rhs);
        return;
      case llvm::Instruction::Shl:
        if (const auto* ci = llvm::dyn_cast<llvm::ConstantInt>(bo.getOperand(1))) {
          int64_t sh = ci->getSExtValue() & 63;
          emitMC(llvm::RISCV::SLLI, { mcReg(dst), mcReg(lhs), mcImm(sh) });
        } else {
          emitMC(llvm::RISCV::SLL, { mcReg(dst), mcReg(lhs), mcReg(rhs) });
        }
        return;
      case llvm::Instruction::AShr:
        if (const auto* ci = llvm::dyn_cast<llvm::ConstantInt>(bo.getOperand(1))) {
          int64_t sh = ci->getSExtValue() & 63;
          emitMC(llvm::RISCV::SRAI, { mcReg(dst), mcReg(lhs), mcImm(sh) });
        } else {
          emitMC(llvm::RISCV::SRA, { mcReg(dst), mcReg(lhs), mcReg(rhs) });
        }
        return;
      case llvm::Instruction::LShr:
        if (const auto* ci = llvm::dyn_cast<llvm::ConstantInt>(bo.getOperand(1))) {
          int64_t sh = ci->getSExtValue() & 63;
          emitMC(llvm::RISCV::SRLI, { mcReg(dst), mcReg(lhs), mcImm(sh) });
        } else {
          emitMC(llvm::RISCV::SRL, { mcReg(dst), mcReg(lhs), mcReg(rhs) });
        }
        return;
      default:
        llvm::report_fatal_error(llvm::Twine("unsupported binary op: ") + bo.getOpcodeName());
    }
  }

  void emitICmpInst(const llvm::ICmpInst& ci)
  {
    llvm::Register dst = vregOf(&ci);
    llvm::Register lhs = emitLoadValue(ci.getOperand(0));
    llvm::Register rhs = emitLoadValue(ci.getOperand(1));
    auto pred = ci.getPredicate();

    switch (pred) {
      case llvm::CmpInst::ICMP_EQ:
        emitVXor(dst, lhs, rhs);
        emitVSltiu(dst, dst, 1);
        return;
      case llvm::CmpInst::ICMP_NE:
        emitVXor(dst, lhs, rhs);
        emitMC(llvm::RISCV::SLTU, { mcReg(dst), mcReg(llvm::Register(llvm::RISCV::X0)), mcReg(dst) });
        return;
      case llvm::CmpInst::ICMP_SLT:
        emitVSlt(dst, lhs, rhs);
        return;
      case llvm::CmpInst::ICMP_SLE:
        emitVSlt(dst, rhs, lhs);
        emitVXori(dst, dst, 1);
        return;
      case llvm::CmpInst::ICMP_SGT:
        emitVSlt(dst, rhs, lhs);
        return;
      case llvm::CmpInst::ICMP_SGE:
        emitVSlt(dst, lhs, rhs);
        emitVXori(dst, dst, 1);
        return;
      case llvm::CmpInst::ICMP_ULT:
        emitMC(llvm::RISCV::SLTU, { mcReg(dst), mcReg(lhs), mcReg(rhs) });
        return;
      case llvm::CmpInst::ICMP_ULE:
        emitMC(llvm::RISCV::SLTU, { mcReg(dst), mcReg(rhs), mcReg(lhs) });
        emitVXori(dst, dst, 1);
        return;
      case llvm::CmpInst::ICMP_UGT:
        emitMC(llvm::RISCV::SLTU, { mcReg(dst), mcReg(rhs), mcReg(lhs) });
        return;
      case llvm::CmpInst::ICMP_UGE:
        emitMC(llvm::RISCV::SLTU, { mcReg(dst), mcReg(lhs), mcReg(rhs) });
        emitVXori(dst, dst, 1);
        return;
      default:
        llvm::report_fatal_error("unsupported icmp predicate");
    }
  }

  void emitLoadInst(const llvm::LoadInst& li)
  {
    llvm::Register dst = vregOf(&li);
    llvm::Register addr = emitLoadValue(li.getPointerOperand());
    llvm::Type* ty = li.getType();
    if (ty->isIntegerTy(32) || ty->isFloatTy())
      emitVLoad32(dst, addr);
    else
      emitVLoad(dst, addr);
  }

  void emitStoreInst(const llvm::StoreInst& si)
  {
    llvm::Register value = emitLoadValue(si.getValueOperand());
    llvm::Register addr = emitLoadValue(si.getPointerOperand());
    llvm::Type* ty = si.getValueOperand()->getType();
    if (ty->isIntegerTy(32) || ty->isFloatTy())
      emitVStore32(value, addr);
    else
      emitVStore(value, addr);
  }

  /*
  ----------------------------------------------------------------
  TASK 5 END
  ----------------------------------------------------------------
  */
'''

result = lines[:start_idx] + (new_code + '\n').split('\n') + lines[end_idx+1:]
# Fix empty split
result = [l for l in result if l is not None]
with open('task/5/EmitMIR.cpp', 'w') as f:
    f.write('\n'.join(result))
print(f"Done: {len(result)} lines")
